import { useQuery } from '@tanstack/react-query';
import React, { useEffect, useState } from 'react'
import { Img_URL, fetchMovie } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import  "../MovieCategory/popular.scss"
const Popular = () => {

    const [page,setPage]=useState(1);

   const loadMoreHandle=()=>{
     setPage(page+1);
   }

    const { isLoading,isError,error ,data: Popular} = useQuery({
        queryKey: ["Movie", "Popular"],
        keepPreviousData: true,
        staleTime:60000,
        queryFn: () =>
          fetchMovie("popular",`${page}`).then((res) => {
            return res.results;
          }),
      });
      useEffect(()=>{

      },[])

      if (isLoading) {
        return (
          <div className="loading">
            <h1>Loading...</h1>
          </div>
        );
      } else if (isError) {
        return (
          <div className="error">
            <p>{error.message}</p>
          </div>
        );
      } else
  return (
    <div className="Popular">
          <h1>Popular Movies</h1>
          <div>
          {Popular?.map((item) => (
              <Link to={`/movie/${item.id}`} className="card" key={item.title}>
                <img src={`${Img_URL}${item.poster_path}`} alt="img" />
              </Link>
          ))}
          </div>
          <button onClick={loadMoreHandle}>More</button>
        </div>
  )
}

export default Popular
